bash_commands.command:
# Apply all @main to @release/2.10 changes in workflows
find .github/workflows -name "*.yml" -exec sed -i 's/@main/@release\/2.10/g' {} \;
find .github/workflows -name "*.yml" -exec sed -i 's/@main/@release\/2.10/g' {} \;

# Also apply to templates
find .github/templates -name "*.j2" -exec sed -i 's/@main/@release\/2.10/g' {} \;
find .github/templates -name "*.j2" -exec sed -i 's/ main / release\/2.10 /g' {} \;

# Also apply to action files  
find .github/actions -name "*.yml" -exec sed -i 's/@main/@release\/2.10/g' {} \;

echo "Applied @main to @release/2.10 conversions"

